mapper.update:
update ai_chat_conversation
set last_message_at = now(), updated_at = now()
where id = #{id}

mapper.select:
select coalesce(max(seq), 0) + 1
from ai_chat_message
where conversation_id = #{conversationId}

select * from ai_chat_message
where conversation_id = #{conversationId}
order by seq asc

    limit #{limit}
